#include <iostream>
#include <queue>
#include <string>
#include <utility>
#include <vector>

int main() {
    std::ios::sync_with_stdio(false);
    std::cin.tie(nullptr);

    int h, w;
    std::cin >> h >> w;
    std::vector<std::string> s(h);
    for (int i = 0; i < h; ++i) std::cin >> s[i];

    std::vector<std::vector<int>> seen(h, std::vector<int>(w, 0));
    const int dr[4] = {1, -1, 0, 0};
    const int dc[4] = {0, 0, 1, -1};
    int ans = 0;

    for (int r = 0; r < h; ++r) {
        for (int c = 0; c < w; ++c) {
            if (s[r][c] == '#' || seen[r][c]) continue;
            bool touches_border = false;
            std::queue<std::pair<int, int>> q;
            q.push({r, c});
            seen[r][c] = 1;
            while (!q.empty()) {
                auto [x, y] = q.front();
                q.pop();
                if (x == 0 || x == h - 1 || y == 0 || y == w - 1) touches_border = true;
                for (int dir = 0; dir < 4; ++dir) {
                    int nx = x + dr[dir], ny = y + dc[dir];
                    if (nx < 0 || nx >= h || ny < 0 || ny >= w) continue;
                    if (s[nx][ny] == '#' || seen[nx][ny]) continue;
                    seen[nx][ny] = 1;
                    q.push({nx, ny});
                }
            }
            if (!touches_border) ++ans;
        }
    }
    std::cout << ans << '\n';
    return 0;
}

