    int n;
    std::cin >> n;
    std::vector<int> a(n), b(n);
    for (int i = 0; i < n; ++i) std::cin >> a[i] >> b[i];

    int m;
    std::cin >> m;
    std::vector<std::string> words(m);
    bool ok[11][11][26] = {};
    for (int i = 0; i < m; ++i) {
        std::cin >> words[i];
        int len = static_cast<int>(words[i].size());
        for (int pos = 1; pos <= len; ++pos) {
            ok[len][pos][words[i][pos - 1] - 'a'] = true;
        }
    }

    for (const std::string& s : words) {
        bool possible = static_cast<int>(s.size()) == n;
        for (int i = 0; i < n && possible; ++i) {
            if (!ok[a[i]][b[i]][s[i] - 'a']) possible = false;
        }
        std::cout << (possible ? "Yes" : "No") << '\n';
    }
    return 0;
}

