int main() {
    std::ios::sync_with_stdio(false);
    std::cin.tie(nullptr);

    int n;
    std::cin >> n;
    std::vector<long long> l(n);
    for (long long& x : l) std::cin >> x;

    int ans = 0;
    int total = 1 << n;
    for (int mask = 0; mask < total; ++mask) {
        long long pos = 1; // 实际坐标 0.5 的两倍。
        int cross = 0;
        for (int i = 0; i < n; ++i) {
            long long next = pos + ((mask >> i) & 1 ? 2 * l[i] : -2 * l[i]);
            if ((pos > 0 && next < 0) || (pos < 0 && next > 0)) ++cross;
            pos = next;
        }
        if (ans < cross) ans = cross;
    }
    std::cout << ans << '\n';
    return 0;
}

