int main() {
    std::ios::sync_with_stdio(false);
    std::cin.tie(nullptr);

    int n, m;
    std::cin >> n >> m;
    std::vector<std::vector<int>> g(n + 1);
    for (int i = 0; i < m; ++i) {
        int a, b;
        std::cin >> a >> b;
        g[a].push_back(b);
    }

    std::vector<int> seen(n + 1, 0);
    std::queue<int> q;
    q.push(1);
    seen[1] = 1;
    int ans = 0;
    while (!q.empty()) {
        int v = q.front();
        q.pop();
        ++ans;
        for (int to : g[v]) {
            if (!seen[to]) {
                seen[to] = 1;
                q.push(to);
            }
        }
    }
    std::cout << ans << '\n';
    return 0;
}

