int main() {
    std::ios::sync_with_stdio(false);
    std::cin.tie(nullptr);

    int n, k;
    std::cin >> n >> k;
    std::unordered_map<long long, long long> cnt;
    cnt.reserve(static_cast<std::size_t>(n) * 2);
    long long total = 0;
    for (int i = 0; i < n; ++i) {
        long long x;
        std::cin >> x;
        total += x;
        ++cnt[x];
    }

    std::vector<long long> gain;
    gain.reserve(cnt.size());
    for (const auto& p : cnt) gain.push_back(p.first * p.second);
    std::sort(gain.begin(), gain.end(), std::greater<long long>());
    for (int i = 0; i < k && i < static_cast<int>(gain.size()); ++i) total -= gain[i];
    std::cout << total << '\n';
    return 0;
}

