#include <iostream>
#include <numeric>
#include <vector>

class DSU {
public:
    explicit DSU(int n) : parent(n), size(n, 1) {
        std::iota(parent.begin(), parent.end(), 0);
    }
    int find(int x) {
        if (parent[x] == x) return x;
        return parent[x] = find(parent[x]);
    }
    void unite(int a, int b) {
        a = find(a); b = find(b);
        if (a == b) return;
        if (size[a] < size[b]) std::swap(a, b);
        parent[b] = a;
        size[a] += size[b];
    }
private:
    std::vector<int> parent, size;
};

int main() {
    std::ios::sync_with_stdio(false);
    std::cin.tie(nullptr);

    int n, m;
    std::cin >> n >> m;
    DSU dsu(n);
    for (int i = 0; i < m; ++i) {
        int a, b;
        std::cin >> a >> b;
        dsu.unite(a - 1, b - 1);
    }
    int comps = 0;
    for (int i = 0; i < n; ++i) {
        if (dsu.find(i) == i) ++comps;
    }
    std::cout << comps - 1 << '\n';
    return 0;
}

