#include <iostream>
#include <string>
#include <vector>

int main() {
    std::ios::sync_with_stdio(false);
    std::cin.tie(nullptr);

    int h, w;
    std::cin >> h >> w;
    std::vector<std::string> a(h);
    int black = 0;
    for (int i = 0; i < h; ++i) {
        std::cin >> a[i];
        for (char ch : a[i]) if (ch == '#') ++black;
    }

    std::vector<std::vector<int>> dp(h, std::vector<int>(w, 0));
    if (a[0][0] == '#') dp[0][0] = 1;
    for (int i = 0; i < h; ++i) {
        for (int j = 0; j < w; ++j) {
            if (a[i][j] != '#') continue;
            if (i > 0 && dp[i - 1][j]) dp[i][j] = 1;
            if (j > 0 && dp[i][j - 1]) dp[i][j] = 1;
        }
    }
    bool ok = (black == h + w - 1) && dp[h - 1][w - 1];
    std::cout << (ok ? "Possible" : "Impossible") << '\n';
    return 0;
}
